// // This module is designed to convert a 10-bit analog input to an 8-bit digital output. It includes an enable signal to control the conversion process. When enabled, the output is the upper 8 bits of the input; otherwise, the output remains at zero.
module ADC_Controller(  
    input wire clk,  
    input wire enable,  
    input wire [9:0] analog_input,  
    output reg [7:0] digital_output  
);  
    always @(posedge clk) begin  
        if (enable) begin  
            digital_output <= analog_input[7:0];  
        end else begin  
            digital_output <= 8'b0;  
        end  
    end  
endmodule
